hudson.tasks.BatchFile.command:
setlocal enabledelayedexpansion

set SRECORD_PATH=C:\srecord\bin
set SRECORD_CMD=%SRECORD_PATH%\Generate_upgrade_bin.bat

cd %WORKSPACE%

REM 取得 bin 檔名
for %%f in (*.bin) do (
    set filename=%%f
    echo "the file is !filename!"
)

REM 利用 - 來分割，取得版本號部分
for /f "tokens=3 delims=-" %%a in ("!filename!") do (
    set version=%%a
    echo "the version is !version!"
)

REM 使用 . 來分割版本號，並存入變數
for /f "tokens=1-4 delims=." %%a in ("!version!") do (
    set v1=%%a
    set v2=%%b
    set v3=%%c
    set v4=%%d
)

REM 將每個數字轉換為十六進位
for %%a in (v1 v2 v3 v4) do (
    set /a high=%%a / 16
    set /a low=%%a %% 16

    REM 處理高位轉換
    if !high! lss 10 (
        set high_char=!high!
    ) else if !high! equ 10 (
        set high_char=A
    ) else if !high! equ 11 (
        set high_char=B
    ) else if !high! equ 12 (
        set high_char=C
    ) else if !high! equ 13 (
        set high_char=D
    ) else if !high! equ 14 (
        set high_char=E
    ) else if !high! equ 15 (
        set high_char=F
    )

    REM 處理低位轉換
    if !low! lss 10 (
        set low_char=!low!
    ) else if !low! equ 10 (
        set low_char=A
    ) else if !low! equ 11 (
        set low_char=B
    ) else if !low! equ 12 (
        set low_char=C
    ) else if !low! equ 13 (
        set low_char=D
    ) else if !low! equ 14 (
        set low_char=E
    ) else if !low! equ 15 (
        set low_char=F
    ) 

    REM 組合高位與低位
    set hex_%%a=!high_char!!low_char!
)

REM 組合成最終結果
set HEX_VERSION=!hex_v1!!hex_v2!!hex_v3!!hex_v4!
echo "hex ver: !HEX_VERSION!"

REM 執行指令將指定的檔頭資料加入 bin file    
%SRECORD_CMD% %WORKSPACE%\!filename! %PRODUCT_NAME% !HEX_VERSION!

REM 將檔案搬移到 jenkins 資料夾
set SRECORD_PATH=C:\srecord\bin
move "%SRECORD_PATH%\*.bin" "%WORKSPACE%\"
cd %WORKSPACE%

REM rename and upload the bin file to OTA server
if "%TO_PRODUCTION%" == "true" (
    if "%PRODUCT_NAME%" == "Reactor_50" (
        rename "*_add_checksum.bin" "stm32_fw_reactor50.bin"
        aws s3 cp stm32_fw_reactor50.bin s3://positivegrid-iot/ota/stm32_fw_reactor50.bin

        if exist "esp32-fw-*.bin" (
            rename "esp32-fw-*.bin" "esp32_fw_reactor50.bin"
            aws s3 cp esp32_fw_reactor50.bin s3://positivegrid-iot/ota/esp32_fw_reactor50.bin
        )
    ) else if "%PRODUCT_NAME%" == "Reactor_100" (
        rename "*_add_checksum.bin" "stm32_fw_reactor100.bin"
        aws s3 cp stm32_fw_reactor100.bin s3://positivegrid-iot/ota/stm32_fw_reactor100.bin

        if exist "esp32-fw-*.bin" (
            rename "esp32-fw-*.bin" "esp32_fw_reactor100.bin"
            aws s3 cp esp32_fw_reactor100.bin s3://positivegrid-iot/ota/esp32_fw_reactor100.bin
        )
    )
) else (
    if "%PRODUCT_NAME%" == "Reactor_50" (
        rename "*_add_checksum.bin" "stm32_fw_reactor50_test.bin"
        aws s3 cp stm32_fw_reactor50_test.bin s3://positivegrid-iot/ota/stm32_fw_reactor50_test.bin

        if exist "esp32-fw-*.bin" (
            rename "esp32-fw-*.bin" "esp32_fw_reactor50_test.bin"
            aws s3 cp esp32_fw_reactor50_test.bin s3://positivegrid-iot/ota/esp32_fw_reactor50_test.bin
        )
    ) else if "%PRODUCT_NAME%" == "Reactor_100" (
        rename "*_add_checksum.bin" "stm32_fw_reactor100_test.bin"
        aws s3 cp stm32_fw_reactor100_test.bin s3://positivegrid-iot/ota/stm32_fw_reactor100_test.bin

        if exist "esp32-fw-*.bin" (
            rename "esp32-fw-*.bin" "esp32_fw_reactor100_test.bin"
            aws s3 cp esp32_fw_reactor100_test.bin s3://positivegrid-iot/ota/esp32_fw_reactor100_test.bin
        )
    )
)
